def gen(rng, size):
    words = []
    cnt = max(1, min(size, 200))
    kinds = ['price', 'price', 'word', 'trail', 'lone', 'mixed']
    for _ in range(cnt):
        k = rng.choice(kinds)
        if k == 'price':
            digits = rng.randrange(1, 11)
            num = ''.join(str(rng.randrange(0, 10)) for _ in range(digits)).lstrip('0') or '0'
            words.append('$' + num)
        elif k == 'word':
            wl = rng.randrange(1, 6)
            words.append(''.join(rng.choice('abcdef') for _ in range(wl)))
        elif k == 'trail':
            words.append(str(rng.randrange(1, 99)) + '$')
        elif k == 'lone':
            words.append('$')
        else:
            words.append('$' + str(rng.randrange(1, 99)) + 'x')
    sentence = ' '.join(words)
    discount = rng.randrange(0, 101)
    return [sentence, discount]

