class Solution:
    def discountPrices(self, sentence, discount):
        out = []
        for w in sentence.split(' '):
            if len(w) >= 2 and w[0] == '$' and w[1:].isdigit():
                price = int(w[1:])
                hundredths = price * (100 - discount)
                dollars = hundredths // 100
                cents = hundredths % 100
                out.append('$' + str(dollars) + '.' + ('0' + str(cents))[-2:])
            else:
                out.append(w)
        return ' '.join(out)

