class Solution:
    def discountPrices(self, sentence, discount):
        factor = 100 - discount
        res = []
        for word in sentence.split(' '):
            if len(word) > 1 and word[0] == '$' and word[1:].isdigit():
                value = int(word[1:]) * factor
                whole = value // 100
                frac = value % 100
                res.append('$%d.%02d' % (whole, frac))
            else:
                res.append(word)
        return ' '.join(res)

